mapper.select:
SELECT a.appointment_date AS date, st.service_type_id, st.type_name AS service_type_name, a.status, COUNT(*) AS count, COALESCE(SUM(a.total_amount), 0) AS total_amount, COALESCE(SUM(a.total_duration), 0) AS total_duration FROM appointment a LEFT JOIN service s ON a.service_id = s.service_id LEFT JOIN service_type st ON s.service_type_id = st.service_type_id
AND a.appointment_date >= #{startDate} AND a.appointment_date <= #{endDate} AND a.status = #{status} AND st.service_type_id = #{serviceTypeId}
GROUP BY a.appointment_date, st.service_type_id, st.type_name, a.status ORDER BY a.appointment_date DESC, st.service_type_id

SELECT st.service_type_id, st.type_name AS service_type_name, COUNT(*) AS count, COALESCE(SUM(a.total_amount), 0) AS total_amount, COALESCE(SUM(a.total_duration), 0) AS total_duration FROM appointment a LEFT JOIN service s ON a.service_id = s.service_id LEFT JOIN service_type st ON s.service_type_id = st.service_type_id
AND a.appointment_date >= #{startDate} AND a.appointment_date <= #{endDate}
GROUP BY st.service_type_id, st.type_name ORDER BY count DESC

SELECT a.status, COUNT(*) AS count, COALESCE(SUM(a.total_amount), 0) AS total_amount, COALESCE(SUM(a.total_duration), 0) AS total_duration FROM appointment a
AND a.appointment_date >= #{startDate} AND a.appointment_date <= #{endDate}
GROUP BY a.status ORDER BY a.status

SELECT DATE(p.payment_time) AS date, p.payment_method, p.payment_status, SUM(CASE WHEN p.payment_status = 1 THEN 1 ELSE 0 END) AS success_count, SUM(CASE WHEN p.payment_status = 1 THEN p.payment_amount ELSE 0 END) AS success_amount, SUM(CASE WHEN p.payment_status = 3 THEN 1 ELSE 0 END) AS refund_count, SUM(CASE WHEN p.payment_status = 3 THEN p.payment_amount ELSE 0 END) AS refund_amount, SUM(CASE WHEN p.payment_status = 1 THEN p.payment_amount ELSE 0 END) - SUM(CASE WHEN p.payment_status = 3 THEN p.payment_amount ELSE 0 END) AS net_revenue FROM payment p
AND DATE(p.payment_time) >= #{startDate} AND DATE(p.payment_time) <= #{endDate} AND p.payment_method = #{paymentMethod}
GROUP BY DATE(p.payment_time), p.payment_method, p.payment_status ORDER BY date DESC

SELECT p.payment_method, SUM(CASE WHEN p.payment_status = 1 THEN 1 ELSE 0 END) AS success_count, SUM(CASE WHEN p.payment_status = 1 THEN p.payment_amount ELSE 0 END) AS success_amount, SUM(CASE WHEN p.payment_status = 3 THEN 1 ELSE 0 END) AS refund_count, SUM(CASE WHEN p.payment_status = 3 THEN p.payment_amount ELSE 0 END) AS refund_amount, SUM(CASE WHEN p.payment_status = 1 THEN p.payment_amount ELSE 0 END) - SUM(CASE WHEN p.payment_status = 3 THEN p.payment_amount ELSE 0 END) AS net_revenue FROM payment p
AND DATE(p.payment_time) >= #{startDate} AND DATE(p.payment_time) <= #{endDate}
GROUP BY p.payment_method ORDER BY net_revenue DESC

SELECT s.staff_id, s.name AS staff_name, SUM(CASE WHEN a.status = 3 THEN 1 ELSE 0 END) AS completed_count, SUM(CASE WHEN a.status = 2 THEN 1 ELSE 0 END) AS in_progress_count, COUNT(*) AS total_count, COALESCE(SUM(a.total_duration), 0) AS total_work_hours, COALESCE(SUM(CASE WHEN a.status = 3 THEN a.total_amount ELSE 0 END), 0) AS total_revenue, COALESCE(AVG(r.overall_rating), 0) AS average_rating, COUNT(DISTINCT r.review_id) AS review_count FROM staff s LEFT JOIN appointment a ON s.staff_id = a.staff_id LEFT JOIN review r ON a.appointment_id = r.appointment_id
AND a.appointment_date >= #{startDate} AND a.appointment_date <= #{endDate} AND s.staff_id = #{staffId}
GROUP BY s.staff_id, s.name HAVING total_count > 0 ORDER BY total_count DESC

SELECT cd.customer_id, cd.name AS customer_name, COUNT(*) AS total_appointments, SUM(CASE WHEN a.status = 3 THEN 1 ELSE 0 END) AS completed_appointments, SUM(CASE WHEN a.status = 4 THEN 1 ELSE 0 END) AS cancelled_appointments, MAX(a.appointment_date) AS last_appointment_date, MIN(a.appointment_date) AS first_appointment_date, COALESCE(SUM(CASE WHEN a.status = 3 THEN a.total_amount ELSE 0 END), 0) AS total_spent, CASE WHEN COUNT(*) >= 10 AND COALESCE(SUM(CASE WHEN a.status = 3 THEN a.total_amount ELSE 0 END), 0) >= 5000 THEN '高活跃' WHEN COUNT(*) >= 5 AND COALESCE(SUM(CASE WHEN a.status = 3 THEN a.total_amount ELSE 0 END), 0) >= 2000 THEN '中活跃' ELSE '低活跃' END AS activity_level FROM customer_detail cd LEFT JOIN appointment a ON cd.customer_id = a.customer_id
AND a.appointment_date >= #{startDate} AND a.appointment_date <= #{endDate} AND cd.customer_id = #{customerId}
GROUP BY cd.customer_id, cd.name HAVING total_appointments > 0 ORDER BY total_appointments DESC, total_spent DESC

SELECT st.service_type_id, st.type_name AS service_type_name, COUNT(r.review_id) AS review_count, COALESCE(AVG(r.overall_rating), 0) AS average_overall_rating, COALESCE(AVG(r.service_attitude_rating), 0) AS average_service_attitude_rating, COALESCE(AVG(r.professional_ability_rating), 0) AS average_professional_ability_rating, COALESCE(AVG(r.service_quality_rating), 0) AS average_service_quality_rating, SUM(CASE WHEN r.overall_rating >= 4.5 THEN 1 ELSE 0 END) AS good_review_count, SUM(CASE WHEN r.overall_rating >= 3.0 AND r.overall_rating < 4.5 THEN 1 ELSE 0 END) AS medium_review_count, SUM(CASE WHEN r.overall_rating < 3.0 THEN 1 ELSE 0 END) AS bad_review_count, CASE WHEN COUNT(r.review_id) > 0 THEN ROUND(SUM(CASE WHEN r.overall_rating >= 4.5 THEN 1 ELSE 0 END) * 100.0 / COUNT(r.review_id), 2) ELSE 0 END AS good_review_rate FROM service_type st LEFT JOIN service s ON st.service_type_id = s.service_type_id LEFT JOIN appointment a ON s.service_id = a.service_id LEFT JOIN review r ON a.appointment_id = r.appointment_id
AND a.appointment_date >= #{startDate} AND a.appointment_date <= #{endDate} AND st.service_type_id = #{serviceTypeId}
GROUP BY st.service_type_id, st.type_name HAVING review_count > 0 ORDER BY average_overall_rating DESC

SELECT s.staff_id, s.name AS staff_name, COUNT(r.review_id) AS review_count, COALESCE(AVG(r.overall_rating), 0) AS average_overall_rating, COALESCE(AVG(r.service_attitude_rating), 0) AS average_service_attitude_rating, COALESCE(AVG(r.professional_ability_rating), 0) AS average_professional_ability_rating, COALESCE(AVG(r.service_quality_rating), 0) AS average_service_quality_rating, SUM(CASE WHEN r.overall_rating >= 4.5 THEN 1 ELSE 0 END) AS good_review_count, SUM(CASE WHEN r.overall_rating >= 3.0 AND r.overall_rating < 4.5 THEN 1 ELSE 0 END) AS medium_review_count, SUM(CASE WHEN r.overall_rating < 3.0 THEN 1 ELSE 0 END) AS bad_review_count, CASE WHEN COUNT(r.review_id) > 0 THEN ROUND(SUM(CASE WHEN r.overall_rating >= 4.5 THEN 1 ELSE 0 END) * 100.0 / COUNT(r.review_id), 2) ELSE 0 END AS good_review_rate FROM staff s LEFT JOIN appointment a ON s.staff_id = a.staff_id LEFT JOIN review r ON a.appointment_id = r.appointment_id
AND a.appointment_date >= #{startDate} AND a.appointment_date <= #{endDate} AND s.staff_id = #{staffId}
GROUP BY s.staff_id, s.name HAVING review_count > 0 ORDER BY average_overall_rating DESC

SELECT st.service_type_id, st.type_name AS service_type_name, COUNT(*) AS count, COALESCE(SUM(a.total_amount), 0) AS total_amount FROM appointment a LEFT JOIN service s ON a.service_id = s.service_id LEFT JOIN service_type st ON s.service_type_id = st.service_type_id
AND a.appointment_date >= #{startDate} AND a.appointment_date <= #{endDate}
GROUP BY st.service_type_id, st.type_name ORDER BY count DESC LIMIT #{limit}

SELECT s.staff_id, s.name AS staff_name, SUM(CASE WHEN a.status = 3 THEN 1 ELSE 0 END) AS completed_count, COUNT(*) AS total_count, COALESCE(SUM(a.total_duration), 0) AS total_work_hours, COALESCE(SUM(CASE WHEN a.status = 3 THEN a.total_amount ELSE 0 END), 0) AS total_revenue, COALESCE(AVG(r.overall_rating), 0) AS average_rating FROM staff s LEFT JOIN appointment a ON s.staff_id = a.staff_id LEFT JOIN review r ON a.appointment_id = r.appointment_id
AND a.appointment_date >= #{startDate} AND a.appointment_date <= #{endDate}
GROUP BY s.staff_id, s.name HAVING total_count > 0 ORDER BY completed_count DESC, total_revenue DESC LIMIT #{limit}

SELECT DATE(p.payment_time) AS date, COALESCE(SUM(CASE WHEN p.payment_status = 1 THEN p.payment_amount ELSE 0 END), 0) AS amount FROM payment p
AND DATE(p.payment_time) >= #{startDate} AND DATE(p.payment_time) <= #{endDate}
GROUP BY DATE(p.payment_time) ORDER BY date ASC

SELECT DATE(a.appointment_date) AS date, COUNT(DISTINCT a.customer_id) AS count FROM appointment a
AND DATE(a.appointment_date) >= #{startDate} AND DATE(a.appointment_date) <= #{endDate}
GROUP BY DATE(a.appointment_date) ORDER BY date ASC

SELECT st.type_name AS serviceTypeName, COUNT(DISTINCT a.appointment_id) AS orderCount, COALESCE(SUM(CASE WHEN p.payment_status = 1 THEN p.payment_amount ELSE 0 END), 0) AS totalRevenue, COUNT(DISTINCT CASE WHEN p.payment_status = 1 THEN a.appointment_id ELSE NULL END) AS paidCount FROM service_type st LEFT JOIN service s ON st.service_type_id = s.service_type_id LEFT JOIN appointment a ON s.service_id = a.service_id LEFT JOIN payment p ON a.appointment_id = p.appointment_id
AND DATE(a.appointment_date) >= #{startDate} AND DATE(a.appointment_date) <= #{endDate}
GROUP BY st.service_type_id, st.type_name HAVING orderCount > 0 ORDER BY orderCount DESC

SELECT p.payment_method, COUNT(*) AS success_count, COALESCE(SUM(p.payment_amount), 0) AS success_amount FROM payment p
AND p.payment_status = 1 AND DATE(p.payment_time) >= #{startDate} AND DATE(p.payment_time) <= #{endDate}
GROUP BY p.payment_method ORDER BY success_amount DESC

SELECT DATE(p.payment_time) AS date, COALESCE(SUM(p.payment_amount), 0) AS amount FROM payment p
AND p.payment_status = 1 AND DATE(p.payment_time) >= #{startDate} AND DATE(p.payment_time) <= #{endDate}
GROUP BY DATE(p.payment_time) ORDER BY date ASC

SELECT a.status, COUNT(DISTINCT a.appointment_id) AS count FROM payment p INNER JOIN appointment a ON p.appointment_id = a.appointment_id
AND p.payment_status = 1 AND DATE(p.payment_time) >= #{startDate} AND DATE(p.payment_time) <= #{endDate}
GROUP BY a.status ORDER BY a.status

SELECT cd.customer_id, cd.name AS customer_name, COUNT(DISTINCT a.appointment_id) AS total_appointments, MAX(DATE(p.payment_time)) AS last_appointment_date, MIN(DATE(p.payment_time)) AS first_appointment_date, COALESCE(SUM(p.payment_amount), 0) AS total_spent, CASE WHEN COUNT(DISTINCT a.appointment_id) >= 10 AND COALESCE(SUM(p.payment_amount), 0) >= 5000 THEN '高活跃' WHEN COUNT(DISTINCT a.appointment_id) >= 5 AND COALESCE(SUM(p.payment_amount), 0) >= 2000 THEN '中活跃' ELSE '低活跃' END AS activity_level FROM payment p INNER JOIN appointment a ON p.appointment_id = a.appointment_id INNER JOIN customer_detail cd ON a.customer_id = cd.customer_id
AND p.payment_status = 1 AND DATE(p.payment_time) >= #{startDate} AND DATE(p.payment_time) <= #{endDate}
GROUP BY cd.customer_id, cd.name HAVING total_appointments > 0 ORDER BY total_appointments DESC, total_spent DESC

SELECT DATE(p.payment_time) AS date, COUNT(DISTINCT a.customer_id) AS count FROM payment p INNER JOIN appointment a ON p.appointment_id = a.appointment_id
AND p.payment_status = 1 AND DATE(p.payment_time) >= #{startDate} AND DATE(p.payment_time) <= #{endDate}
GROUP BY DATE(p.payment_time) ORDER BY date ASC

SELECT COALESCE(s.service_name, '未分类') AS serviceTypeName, COUNT(DISTINCT a.appointment_id) AS orderCount, COALESCE(SUM(p.payment_amount), 0) AS totalRevenue, COUNT(DISTINCT a.appointment_id) AS paidCount FROM payment p INNER JOIN appointment a ON p.appointment_id = a.appointment_id LEFT JOIN service s ON a.service_id = s.service_id
AND p.payment_status = 1 AND DATE(p.payment_time) >= #{startDate} AND DATE(p.payment_time) <= #{endDate}
GROUP BY s.service_id, s.service_name HAVING orderCount > 0 ORDER BY orderCount DESC

SELECT st.service_type_id, st.type_name AS service_type_name, COUNT(r.review_id) AS review_count, COALESCE(AVG(r.overall_rating), 0) AS average_overall_rating, COALESCE(AVG(r.service_attitude_rating), 0) AS average_service_attitude_rating, COALESCE(AVG(r.professional_ability_rating), 0) AS average_professional_ability_rating, COALESCE(AVG(r.service_quality_rating), 0) AS average_service_quality_rating, SUM(CASE WHEN r.overall_rating >= 4.5 THEN 1 ELSE 0 END) AS good_review_count, SUM(CASE WHEN r.overall_rating >= 3.0 AND r.overall_rating < 4.5 THEN 1 ELSE 0 END) AS medium_review_count, SUM(CASE WHEN r.overall_rating < 3.0 THEN 1 ELSE 0 END) AS bad_review_count, CASE WHEN COUNT(r.review_id) > 0 THEN ROUND(SUM(CASE WHEN r.overall_rating >= 4.5 THEN 1 ELSE 0 END) * 100.0 / COUNT(r.review_id), 2) ELSE 0 END AS good_review_rate FROM payment p INNER JOIN appointment a ON p.appointment_id = a.appointment_id LEFT JOIN service s ON a.service_id = s.service_id LEFT JOIN service_type st ON s.service_type_id = st.service_type_id LEFT JOIN review r ON a.appointment_id = r.appointment_id
AND p.payment_status = 1 AND DATE(p.payment_time) >= #{startDate} AND DATE(p.payment_time) <= #{endDate} AND st.service_type_id = #{serviceTypeId}
GROUP BY st.service_type_id, st.type_name HAVING review_count > 0 ORDER BY average_overall_rating DESC
